import{_ as t,o as r,c as s,ag as a}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Projets","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/projects.md","filePath":"fr/features/projects.md"}'),o={name:"fr/features/projects.md"};function i(l,e,n,u,d,p){return r(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="projets" tabindex="-1">Projets <a class="header-anchor" href="#projets" aria-label="Permalink to &quot;Projets&quot;">​</a></h1><p>Organisez votre travail en projets pour suivre le temps, le chiffre d&#39;affaires et la rentabilite par engagement.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>Les projets vous aident a regrouper factures, depenses et entrees de temps. Cela vous donne une vision claire de la rentabilite de chaque projet ou engagement client.</p><h2 id="creer-un-projet" tabindex="-1">Creer un projet <a class="header-anchor" href="#creer-un-projet" aria-label="Permalink to &quot;Creer un projet&quot;">​</a></h2><ol><li>Allez dans <strong>Projets &gt; Nouveau projet</strong></li><li>Remplissez : <ul><li><strong>Nom</strong> -- Un nom de projet clair</li><li><strong>Client</strong> -- Le client concerne par ce projet</li><li><strong>Description</strong> -- Ce que le projet implique</li><li><strong>Budget</strong> -- Montant du budget optionnel</li><li><strong>Statut</strong> -- Actif, En pause ou Termine</li></ul></li><li>Cliquez sur <strong>Enregistrer</strong></li></ol><h2 id="statuts-des-projets" tabindex="-1">Statuts des projets <a class="header-anchor" href="#statuts-des-projets" aria-label="Permalink to &quot;Statuts des projets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Statut</th><th>Description</th></tr></thead><tbody><tr><td><strong>Actif</strong></td><td>En cours de realisation</td></tr><tr><td><strong>En pause</strong></td><td>Temporairement suspendu</td></tr><tr><td><strong>Termine</strong></td><td>Fini -- plus de travail prevu</td></tr><tr><td><strong>Archive</strong></td><td>Conserve pour reference</td></tr></tbody></table><h2 id="page-de-detail-du-projet" tabindex="-1">Page de detail du projet <a class="header-anchor" href="#page-de-detail-du-projet" aria-label="Permalink to &quot;Page de detail du projet&quot;">​</a></h2><p>La page de detail du projet affiche :</p><ul><li><strong>Vue d&#39;ensemble</strong> -- Nom, client, statut, budget</li><li><strong>Factures liees</strong> -- Toutes les factures liees a ce projet</li><li><strong>Depenses liees</strong> -- Couts attribues a ce projet</li><li><strong>Entrees de temps</strong> -- Heures enregistrees sur ce projet</li><li><strong>Rentabilite</strong> -- Ventilation revenus vs. couts</li></ul><h2 id="lier-des-elements-aux-projets" tabindex="-1">Lier des elements aux projets <a class="header-anchor" href="#lier-des-elements-aux-projets" aria-label="Permalink to &quot;Lier des elements aux projets&quot;">​</a></h2><p>Lors de la creation de factures, depenses ou entrees de temps, selectionnez le projet dans le menu deroulant pour les lier. Cela met automatiquement a jour les donnees financieres du projet.</p><ul><li><strong>Factures</strong> -- Suivez le chiffre d&#39;affaires par projet</li><li><strong>Depenses</strong> -- Suivez les couts par projet</li><li><strong>Entrees de temps</strong> -- Suivez les heures par projet</li></ul><h2 id="suivi-du-budget" tabindex="-1">Suivi du budget <a class="header-anchor" href="#suivi-du-budget" aria-label="Permalink to &quot;Suivi du budget&quot;">​</a></h2><p>Si vous definissez un budget :</p><ul><li>Voyez quelle part du budget a ete utilisee</li><li>Suivez le budget restant</li><li>Comparez les couts reels au budget</li><li>Recevez des alertes lorsque vous approchez des limites du budget</li></ul><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><ul><li><strong>Changer le statut</strong> -- Mettez a jour plusieurs projets a la fois</li><li><strong>Archiver</strong> -- Deplacez les projets termines vers les archives</li><li><strong>Restaurer</strong> -- Recuperez les projets archives</li></ul><h2 id="rapports" tabindex="-1">Rapports <a class="header-anchor" href="#rapports" aria-label="Permalink to &quot;Rapports&quot;">​</a></h2><p>Consultez la performance des projets dans les <a href="/fr/features/reports">rapports clients</a> pour voir :</p><ul><li>Chiffre d&#39;affaires par projet</li><li>Temps passe par projet</li><li>Marges beneficiaires</li><li>Comparaison entre projets</li></ul><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Utilisez les projets meme pour les petits engagements -- les analyses sont precieuses</li><li>Liez a la fois les factures et les depenses pour obtenir des marges beneficiaires precises</li><li>Archivez les projets termines pour garder votre liste active propre</li><li>Consultez le profil de tableau de bord base sur les projets pour une vue axee sur les projets</li></ul>',24)])])}const h=t(o,[["render",i]]);export{g as __pageData,h as default};
